class Stack {
    constructor() {
        this.items = [];
    }

    push(ele) {
        this.items.push(ele);
    }

    pop() {
        if (this.isEmpty()) {
            return -1;
        }
        return this.items.pop();
    }

    isEmpty() {
        return this.items.length === 0;
    }
}

function decimalToBinary(decimal) {
    let stack = new Stack();

    if (decimal === 0) {
        console.log("0");
        return;
    }

    while (decimal > 0) {
        let remainder = decimal % 2;
        stack.push(remainder);
        decimal = Math.floor(decimal / 2);
    }

    let binaryString = "";
    while (!stack.isEmpty()) {
        binaryString += stack.pop();
    }
    console.log(binaryString);
}

function main() {
    const readline = require('readline');
    const rl = readline.createInterface({
        input: process.stdin,
        output: process.stdout,
        terminal: false
    });

    let testCases = [];

    rl.question('', (t) => {
        t = parseInt(t);

        rl.on('line', (line) => {
            testCases.push(parseInt(line.trim()));
            if (testCases.length === t) {
                rl.close();
            }
        });
    });

    rl.on('close', () => {
        testCases.forEach(decimalToBinary);
    });
}

main();
